INSERT INTO `llx_commandedet` VALUES (1,1,NULL,NULL,NULL,'Pour les sites *-caribara.com \r\nAdaptation interfaces (autoplay)\r\nmontรฉe de niveau php\r\n\r\n4 jours','',20.000,0.000,'0',0.000,'0',4,0,0,NULL,720,720.00000000,2880.00000000,576.00000000,0.00000000,0.00000000,3456.00000000,0,NULL,NULL,0,0.00000000,NULL,0,1,NULL,NULL,NULL,0,'EUR',720.00000000,2880.00000000,576.00000000,3456.00000000),(2,2,NULL,NULL,NULL,'mise en place d\'un site Wordpress \"vierge\" pour https://www.securite-des-si.com/\r\ncrรฉation de l\'espace de travail sur le serveur de production 51.83.111.21 (certificats, archivage, sftp, ..)\r\naide ร  la configuration d\'un espace de travail accessible uniquement pour Marie-Pier via la modification du fichier hosts\r\nmise en place d\'un site https://preprod.securite-des-si.com/ , crรฉรฉ par recopie du site , en remplacant www.securite-des-si.com par preprod.securite-des-si.com dans les tables habituelles  (cela signifie que la copie peut faire des rรฉfรฉrences ร   des contenus en production, si il y a des plugins exotiques qui stockent leurs donnรฉes ailleurs) -> cela permettra d\'avoir un espace de test pour l\'intรฉgration de plugin ou des rรฉglages de themes, qui ne viennent pas casser le site de production','',20.000,0.000,'0',0.000,'0',5,0,0,NULL,90,90.00000000,450.00000000,90.00000000,0.00000000,0.00000000,540.00000000,1,NULL,NULL,0,0.00000000,NULL,0,1,NULL,NULL,NULL,0,'EUR',90.00000000,450.00000000,90.00000000,540.00000000);
