INSERT INTO `llx_propaldet` VALUES (1,1,NULL,NULL,NULL,'Outil de gestion \"back-office\" de contenu de elearning\r\n\r\nInstallation d\'un serveur de test/recette/preprod \r\nMise en place d\'un depot github\r\nScript de migration/mise en recette automatique depuis le git\r\n\r\nInstallation du serveur de prod ร  votre charge (pour que vous validiez le process vous-mรชme), avec notre soutien\r\n1 journรฉe',NULL,'',20.000,0.000,'0',0.000,'0',1,0,0,750,750.00000000,750.00000000,150.00000000,0.00000000,0.00000000,900.00000000,0,NULL,NULL,0,0.00000000,NULL,0,1,NULL,NULL,'EUR',750.00000000,750.00000000,150.00000000,900.00000000),(2,1,NULL,NULL,NULL,'Hรฉbergement serveur test/recette (machine moyenne chez gandi), prix pour un an',NULL,'',20.000,0.000,'0',0.000,'0',12,0,0,NULL,35.00000000,420.00000000,84.00000000,0.00000000,0.00000000,504.00000000,0,NULL,NULL,0,0.00000000,NULL,0,2,NULL,NULL,'EUR',35.00000000,420.00000000,84.00000000,504.00000000),(3,1,NULL,NULL,NULL,'Architecture des modules : \r\nunitรฉ รฉlementaire : question+reponses (textes html + medias)\r\norganisรฉes en collection (suite ordonnรฉes de questions)\r\nversionnage des questions et colelctions\r\nconstruction d\'une base de donnรฉes nosql idoine (medias intรฉgrรฉs en blob)\r\nExport vers csv',NULL,'',20.000,0.000,'0',0.000,'0',1,0,0,750,750.00000000,750.00000000,150.00000000,0.00000000,0.00000000,900.00000000,0,NULL,NULL,0,0.00000000,NULL,0,3,NULL,NULL,'EUR',750.00000000,750.00000000,150.00000000,900.00000000),(4,1,NULL,NULL,NULL,'mise en place d\'un portail (login, gestion simple de droits, menus dynamique)\r\nWordpress ou Dolibarr, ou autre ร  dรฉfinir',NULL,'',20.000,0.000,'0',0.000,'0',1,0,0,NULL,750.00000000,750.00000000,150.00000000,0.00000000,0.00000000,900.00000000,0,NULL,NULL,0,0.00000000,NULL,0,4,NULL,NULL,'EUR',750.00000000,750.00000000,150.00000000,900.00000000),(5,1,NULL,NULL,NULL,'Systรจme de logs\r\nNous mettrons en place un service Matomo, et intรฉgrerons des appels ร  celui-ci en passant le maximum de parametres. Les dashboard et outils de reporting de Matomo permettront de voir apparaitre beaucoup d\'anomalies le cas รฉchรฉant, des outils complรฉmentaires pourront รชtre branchรฉs sur la base de donnรฉes des รฉvenements',NULL,'',20.000,0.000,'0',0.000,'0',1,0,0,750,750.00000000,750.00000000,150.00000000,0.00000000,0.00000000,900.00000000,0,NULL,NULL,0,0.00000000,NULL,0,5,NULL,NULL,'EUR',750.00000000,750.00000000,150.00000000,900.00000000),(6,1,NULL,NULL,NULL,'Brique \"gestion des droits\"\r\nPermet de donner aux experts des droits de lecture /modifications/creations sur des collections et/ou questions + autorisation de chgt de statut (brouillon ร  valider, validรฉ, pulbiรฉ)\r\nDans le contexte, il faut envisager d\'avoir uniquement ร  expliciter de maniรจre positive les droits (pas de \"tous sauf ..\")\r\nChaque autorisation a une durรฉe de vie (dรฉfaut 21 jours par exemple)\r\n\r\nReporting visualisation les comptes existants avec une synthรจse de leur droits actuels',NULL,'',20.000,0.000,'0',0.000,'0',2,0,0,750,750.00000000,1500.00000000,300.00000000,0.00000000,0.00000000,1800.00000000,0,NULL,NULL,0,0.00000000,NULL,0,6,NULL,NULL,'EUR',750.00000000,1500.00000000,300.00000000,1800.00000000),(7,1,NULL,NULL,NULL,'Interface expert\r\nDonne accรจs aux experts uniquement aux collections ou questions auxquelles ils ont droits\r\nMode collections : ajout suppression d\'une question, chgt d\'ordre par drag and drop\r\nMode questions : รฉdition html d\'un texte + media, des rรฉponses (textes html + medias)\r\nChangement de statut des questions ou colelctions\r\nLien pour visualisations dans plusieurs tailles d\'รฉcrans',NULL,'',20.000,0.000,'0',0.000,'0',4,0,0,750,750.00000000,3000.00000000,600.00000000,0.00000000,0.00000000,3600.00000000,0,NULL,NULL,0,0.00000000,NULL,0,7,NULL,NULL,'EUR',750.00000000,3000.00000000,600.00000000,3600.00000000),(8,1,NULL,NULL,NULL,'Workflow \r\nchaque collection a un statut et un responsable pour action, ainsi qu\'un responsab